import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicMixed() {
        // Sorted by end: [1,4],[3,5],[0,6],[5,7],[5,9],[8,9]
        // Pick [1,4] end=4; [5,7] start=5>=4 pick end=7; [8,9] start=8>=7 pick end=9 => 3
        assertEquals(3, new Solution().maxActivities(new int[][]{{1,4},{3,5},{0,6},{5,7},{8,9},{5,9}}));
    }

    @Test
    void allDisjoint() {
        // [1,2],[3,4],[5,6],[7,8] — completely disjoint, pick all 4
        assertEquals(4, new Solution().maxActivities(new int[][]{{1,2},{3,4},{5,6},{7,8}}));
    }

    @Test
    void oneActivityDominates() {
        // [1,10] spans everything; greedy picks the short ones instead
        assertEquals(3, new Solution().maxActivities(new int[][]{{1,10},{2,3},{4,5},{6,7}}));
    }

    @Test
    void endpointTouchAllowed() {
        // [1,3] and [3,5] share endpoint 3 — NOT an overlap, both selected
        assertEquals(2, new Solution().maxActivities(new int[][]{{1,3},{3,5}}));
    }

    @Test
    void allOverlapping() {
        // All span [1,5] — only one can be selected
        assertEquals(1, new Solution().maxActivities(new int[][]{{1,5},{1,5},{1,5},{1,5}}));
    }

    @Test
    void singleActivity() {
        assertEquals(1, new Solution().maxActivities(new int[][]{{2,8}}));
    }

    @Test
    void emptyInput() {
        assertEquals(0, new Solution().maxActivities(new int[][]{}));
    }
}
